def answer_one_question(context_q: str, verification_q: str) -> str:
    return client.messages.create(
        model="claude-sonnet-4-6",
        max_tokens=512,
        messages=[{
            "role": "user",
            "content": (
                f"Background context: {context_q}\n\n"
                f"Answer this specific question concisely and factually:\n{verification_q}"
            ),
        }],
    ).content[0].text.strip()

def answer_verification_questions(
    original_question: str,
    verification_questions: list[str],
) -> list[str]:
    # CRITICAL: The draft is NOT passed here.
    # Each question is answered fresh without seeing the draft.
    # This avoids anchoring where the model confirms its own draft.
    with ThreadPoolExecutor(max_workers=len(verification_questions)) as pool:
        answers = list(pool.map(
            lambda q: answer_one_question(original_question, q),
            verification_questions,
        ))
    return answers

# With 5 questions and ~1.5s per call:
# Sequential: ~7.5s   Parallel: ~1.5s  (5x speedup)

REVISION_PROMPT = """You wrote an initial response to a question.
You then answered verification questions about it independently.
Some answers may contradict your original response.

Original question: {question}

Your initial response:
{draft}

Verification Q&A:
{qa_pairs}

Write a revised final response. Correct any factual errors identified by the
verification answers. Keep everything correct unchanged.
If no corrections are needed, reproduce the original response unchanged.
Do not mention the verification process in your final response."""

def revise_with_verification_results(
    question: str,
    draft: str,
    verification_questions: list[str],
    verification_answers: list[str],
) -> str:
    qa_text = "\n".join(
        f"Q{i+1}: {q}\nA{i+1}: {a}"
        for i, (q, a) in enumerate(zip(verification_questions, verification_answers))
    )
    return client.messages.create(
        model="claude-sonnet-4-6",
        max_tokens=2048,
        messages=[{"role": "user", "content": REVISION_PROMPT.format(
            question=question, draft=draft, qa_pairs=qa_text,
        )}],
    ).content[0].text
